data.query:
mutation CustomerSendAccountInviteEmail($customerId: ID!, $email: EmailInput) {
    customerSendAccountInviteEmail(customerId: $customerId, email: $email) {
        customer {
            id
            firstName
            lastName
            displayName
            state
            createdAt
            updatedAt
        }
        userErrors {
            field
            message
        }
    }
}
